<template>
    <el-dialog :visible.sync="visible" title="详情页" :fullscreen="autoOpen" :show-close="!autoOpen">
        <el-form>
            <el-form-item></el-form-item>
        </el-form>
    </el-dialog>
</template>
<script>
    export default {
        data() {
            return {
                autoOpen: !!+this.$route.query.show,
                visible: !!+this.$route.query.show,
            }
        },
        methods: {
            show() {
                this.visible = true;
            }
        }
    }
</script>
